import React, { useState, useRef, useEffect } from 'react';
import { Link as RouterLink } from 'react-router-dom';
import {
  Box,
  Button,
  Container,
  Typography,
  Grid,
  Card,
  CardContent,
  Stack,
  Paper,
  useTheme,
  Avatar,
  Chip,
  Fade,
  Divider,
  IconButton,
  useMediaQuery,
  TextField,
  Stepper,
  Step,
  StepLabel,
  StepButton,
  LinearProgress
} from '@mui/material';
import AutoAwesomeIcon from '@mui/icons-material/AutoAwesome';
import ArrowForwardIcon from '@mui/icons-material/ArrowForward';
import StarIcon from '@mui/icons-material/Star';
import CheckCircleIcon from '@mui/icons-material/CheckCircle';
import PlayArrowIcon from '@mui/icons-material/PlayArrow';
import VerifiedUserIcon from '@mui/icons-material/VerifiedUser';
import FormatQuoteIcon from '@mui/icons-material/FormatQuote';
import EditIcon from '@mui/icons-material/Edit';
import SendIcon from '@mui/icons-material/Send';
import WarningAmberIcon from '@mui/icons-material/WarningAmber';
import TipsAndUpdatesIcon from '@mui/icons-material/TipsAndUpdates';
import VerifiedIcon from '@mui/icons-material/Verified';
import CelebrationOutlinedIcon from '@mui/icons-material/CelebrationOutlined';
import { keyframes } from '@mui/system';

const TestimonialMascot = ({ size = 'medium', color = 'primary' }) => {
  const theme = useTheme();
  const sizeMap = {
    small: { width: 40, height: 40, quoteSize: 'small' },
    medium: { width: 60, height: 60, quoteSize: 'medium' },
    large: { width: 80, height: 80, quoteSize: 'large' }
  };

  const dims = sizeMap[size];

  return (
    <Box
      sx={{
        position: 'relative',
        width: dims.width,
        height: dims.height,
        display: 'inline-flex',
        alignItems: 'center',
        justifyContent: 'center'
      }}
    >
      {/* Speech bubble shape */}
      <Box
        sx={{
          width: '100%',
          height: '100%',
          borderRadius: '50%',
          background: theme => theme.palette[color].main,
          position: 'relative',
          '&::after': {
            content: '""',
            position: 'absolute',
            bottom: '-10px',
            right: '10px',
            width: '20px',
            height: '20px',
            background: theme => theme.palette[color].main,
            borderRadius: '50%',
            transform: 'scale(0.5)'
          },
          '&::before': {
            content: '""',
            position: 'absolute',
            bottom: '-18px',
            right: '0',
            width: '15px',
            height: '15px',
            background: theme => theme.palette[color].main,
            borderRadius: '50%',
            transform: 'scale(0.3)'
          }
        }}
      />

      {/* Quote icon */}
      <FormatQuoteIcon 
        sx={{ 
          position: 'absolute', 
          color: 'white',
          transform: 'rotate(180deg)',
          fontSize: dims.quoteSize === 'small' ? '1.5rem' : 
                   dims.quoteSize === 'medium' ? '2rem' : '2.5rem'
        }} 
      />

      {/* Eyes */}
      <Box
        sx={{
          position: 'absolute',
          top: '30%',
          left: '25%',
          width: '8px',
          height: '8px',
          borderRadius: '50%',
          background: 'white'
        }}
      />
      <Box
        sx={{
          position: 'absolute',
          top: '30%',
          right: '25%',
          width: '8px',
          height: '8px',
          borderRadius: '50%',
          background: 'white'
        }}
      />

      {/* Smile */}
      <Box
        sx={{
          position: 'absolute',
          bottom: '30%',
          left: '50%',
          transform: 'translateX(-50%)',
          width: '20px',
          height: '10px',
          borderBottomLeftRadius: '10px',
          borderBottomRightRadius: '10px',
          border: '2px solid white',
          borderTop: 'none'
        }}
      />
    </Box>
  );
};

const TestimonialStarMascot = ({ size = 'medium', color = 'primary' }) => {
  const sizeMap = {
    small: { width: 40, height: 40 },
    medium: { width: 60, height: 60 },
    large: { width: 80, height: 80 }
  };

  const dims = sizeMap[size];

  return (
    <Box
      sx={{
        position: 'relative',
        width: dims.width,
        height: dims.height,
        display: 'inline-flex',
        alignItems: 'center',
        justifyContent: 'center'
      }}
    >
      {/* Star shape */}
      <StarIcon 
        sx={{ 
          position: 'absolute',
          width: '100%',
          height: '100%',
          color: theme => theme.palette[color].main,
          filter: 'drop-shadow(0 2px 5px rgba(0,0,0,0.2))'
        }} 
      />

      {/* Eyes */}
      <Box
        sx={{
          position: 'absolute',
          top: '35%',
          left: '30%',
          width: '6px',
          height: '6px',
          borderRadius: '50%',
          background: 'white'
        }}
      />
      <Box
        sx={{
          position: 'absolute',
          top: '35%',
          right: '30%',
          width: '6px',
          height: '6px',
          borderRadius: '50%',
          background: 'white'
        }}
      />

      {/* Smile */}
      <Box
        sx={{
          position: 'absolute',
          bottom: '35%',
          left: '50%',
          transform: 'translateX(-50%)',
          width: '16px',
          height: '8px',
          borderBottomLeftRadius: '8px',
          borderBottomRightRadius: '8px',
          border: '2px solid white',
          borderTop: 'none'
        }}
      />
    </Box>
  );
};

const subtleShakeAnimation = keyframes`
  0% { transform: translateX(0); }
  25% { transform: translateX(-2px); }
  50% { transform: translateX(0); }
  75% { transform: translateX(2px); }
  100% { transform: translateX(0); }
`;

const PersonDoodle1 = () => (
  <Box
    component="svg"
    xmlns="http://www.w3.org/2000/svg"
    viewBox="0 0 200 200"
    sx={{
      position: 'absolute',
      width: { xs: '120px', md: '150px' },
      height: 'auto',
      right: { xs: '-20px', md: '5%' },
      top: { xs: '10%', md: '15%' },
      opacity: 0.8,
      zIndex: 0,
      display: { xs: 'none', sm: 'block' }
    }}
  >
    <path
      d="M80,40 Q95,30 110,40 Q120,45 125,60 Q130,80 120,90 Q110,100 90,95 Q75,90 70,75 Q65,60 80,40"
      fill="none"
      stroke="#000"
      strokeWidth="1.5"
    />
    <path
      d="M100,90 L100,130 Q100,150 85,170"
      fill="none"
      stroke="#000"
      strokeWidth="1.5"
    />
    <path
      d="M100,130 Q115,140 120,160"
      fill="none"
      stroke="#000"
      strokeWidth="1.5"
    />
    <path
      d="M85,110 L65,130"
      fill="none"
      stroke="#000"
      strokeWidth="1.5"
    />
    <path
      d="M115,110 L135,130"
      fill="none"
      stroke="#000"
      strokeWidth="1.5"
    />
    <circle cx="95" cy="55" r="2" fill="#000" />
    <circle cx="115" cy="55" r="2" fill="#000" />
    <path
      d="M95,70 Q105,75 115,70"
      fill="none"
      stroke="#000"
      strokeWidth="1.5"
    />
    <circle cx="105" cy="45" r="5" fill="#4F46E5" opacity="0.7" />
  </Box>
);

const PersonDoodle2 = () => (
  <Box
    component="svg"
    xmlns="http://www.w3.org/2000/svg"
    viewBox="0 0 200 200"
    sx={{
      position: 'absolute',
      width: { xs: '120px', md: '150px' },
      height: 'auto',
      left: { xs: '-20px', md: '5%' },
      bottom: { xs: '5%', md: '10%' },
      opacity: 0.8,
      zIndex: 0,
      display: { xs: 'none', sm: 'block' }
    }}
  >
    <path
      d="M90,40 Q105,30 120,40 Q130,50 125,70 Q120,85 105,90 Q90,95 80,80 Q75,65 90,40"
      fill="none"
      stroke="#000"
      strokeWidth="1.5"
    />
    <path
      d="M105,90 L105,140 Q105,160 120,180"
      fill="none"
      stroke="#000"
      strokeWidth="1.5"
    />
    <path
      d="M105,140 Q90,150 80,170"
      fill="none"
      stroke="#000"
      strokeWidth="1.5"
    />
    <path
      d="M90,110 Q75,100 60,110"
      fill="none"
      stroke="#000"
      strokeWidth="1.5"
    />
    <path
      d="M120,110 Q135,115 150,105"
      fill="none"
      stroke="#000"
      strokeWidth="1.5"
    />
    <circle cx="95" cy="55" r="2" fill="#000" />
    <circle cx="115" cy="55" r="2" fill="#000" />
    <path
      d="M95,70 Q105,75 115,70"
      fill="none"
      stroke="#000"
      strokeWidth="1.5"
    />
    <path
      d="M150,105 L170,95"
      fill="none"
      stroke="#000"
      strokeWidth="1.5"
    />
    <path
      d="M170,95 Q175,93 180,100"
      fill="none"
      stroke="#000"
      strokeWidth="1.5"
    />
    <rect x="175" y="95" width="15" height="20" rx="2" fill="none" stroke="#000" strokeWidth="1.5" />
    <line x1="178" y1="100" x2="187" y2="100" stroke="#4F46E5" strokeWidth="1.5" />
    <line x1="178" y1="105" x2="187" y2="105" stroke="#4F46E5" strokeWidth="1.5" />
    <line x1="178" y1="110" x2="187" y2="110" stroke="#4F46E5" strokeWidth="1.5" />
  </Box>
);

const QuoteDoodle = () => (
  <Box
    component="svg"
    xmlns="http://www.w3.org/2000/svg"
    viewBox="0 0 100 100"
    sx={{
      position: 'absolute',
      width: { xs: '80px', md: '100px' },
      height: 'auto',
      right: { xs: '5%', md: '15%' },
      bottom: { xs: '30%', md: '40%' },
      opacity: 0.8,
      zIndex: 0,
      display: { xs: 'none', sm: 'block' }
    }}
  >
    <path
      d="M30,30 Q40,20 50,30 Q60,40 50,50 Q40,60 30,50 Q20,40 30,30"
      fill="none"
      stroke="#000"
      strokeWidth="1.5"
    />
    <path
      d="M35,35 L35,45 L45,45 L45,35 Z"
      fill="#4F46E5"
      opacity="0.2"
    />
    <path
      d="M60,50 Q70,40 80,50 Q90,60 80,70 Q70,80 60,70 Q50,60 60,50"
      fill="none"
      stroke="#000"
      strokeWidth="1.5"
    />
    <path
      d="M65,55 L65,65 L75,65 L75,55 Z"
      fill="#4F46E5"
      opacity="0.2"
    />
  </Box>
);

const HomePage = () => {
  const theme = useTheme();
  const isMobile = useMediaQuery(theme.breakpoints.down('md'));
  const [activeStep, setActiveStep] = useState(0);
  const [completed, setCompleted] = useState({});
  const [originalScores, setOriginalScores] = useState({ emotional: 0, specificity: 0, credibility: 0 });
  const [enhancedScores, setEnhancedScores] = useState({ emotional: 0, specificity: 0, credibility: 0 });
  const [spotlightActive, setSpotlightActive] = useState(false);
  const [shakeEnhanceButton, setShakeEnhanceButton] = useState(false);

  const steps = [
    'Enter original testimonial',
    'Get AI enhancement',
    'Client verification'
  ];

  const originalText = "The coaching was good. I learned some things that helped me.";
  const enhancedText = "Working with Sarah transformed my approach to challenges. I went from feeling stuck to landing two major clients in just 3 weeks. Her coaching didn't just teach me tactics—it changed my entire mindset about what's possible.";

  const handleStep = (step) => () => {
    setActiveStep(step);

    // Mark previous steps as completed
    const newCompleted = {...completed};
    for (let i = 0; i < step; i++) {
      newCompleted[i] = true;
    }
    setCompleted(newCompleted);
  };

  const handleNext = () => {
    const newCompleted = {...completed};
    newCompleted[activeStep] = true;
    setCompleted(newCompleted);
    setActiveStep((prevActiveStep) => prevActiveStep + 1);
  };

  const handleReset = () => {
    setActiveStep(0);
    setCompleted({});
    setOriginalScores({ emotional: 0, specificity: 0, credibility: 0 });
    setEnhancedScores({ emotional: 0, specificity: 0, credibility: 0 });
    setSpotlightActive(false);
  };

  const getScoreColor = (score) => {
    if (score < 50) return 'error.main';
    if (score < 75) return 'warning.main';
    return 'success.main';
  };

  const handleTryDemo = () => {
    setSpotlightActive(true);

    // Shake the enhance button
    setShakeEnhanceButton(true);
    setTimeout(() => setShakeEnhanceButton(false), 1500);

    // Scroll to demo on mobile
    if (isMobile && demoRef.current) {
      demoRef.current.scrollIntoView({ 
        behavior: 'smooth',
        block: 'center'
      });
    }

    // Auto-dismiss spotlight after 3 seconds
    setTimeout(() => {
      setSpotlightActive(false);
    }, 3000);
  };

  const demoRef = useRef(null);

  return (
    <Box sx={{ overflow: 'hidden' }}>
      <Box sx={{ position: 'relative', overflow: 'hidden' }}>
        <PersonDoodle1 />
        <Container maxWidth="lg">
          {/* Hero Section */}
          <Box 
            sx={{
              pt: { xs: 6, md: 8 },
              pb: { xs: 8, md: 10 },
              position: 'relative',
              minHeight: '80vh',
              display: 'flex',
              alignItems: 'center'
            }}
          >
            {/* Background gradient */}
            <Box 
              sx={{
                position: 'absolute',
                top: 0,
                left: 0,
                right: 0,
                bottom: 0,
                background: 'linear-gradient(180deg, rgba(93, 95, 239, 0.05) 0%, rgba(93, 95, 239, 0) 100%)',
                zIndex: -1
              }}
            />

            <Box sx={{ display: 'flex', flexDirection: { xs: 'column', md: 'row' }, alignItems: 'center' }}>
              {/* Left side - Hero text */}
              <Box sx={{ width: { xs: '100%', md: '50%' }, pr: { md: 6 }, mb: { xs: 6, md: 0 } }}>
                <Chip
                  icon={<AutoAwesomeIcon />}
                  label="AI-Powered Testimonials"
                  sx={{ 
                    mb: 3, 
                    bgcolor: 'primary.light', 
                    color: 'primary.dark',
                    fontWeight: 600,
                    '& .MuiChip-icon': { color: 'primary.main' }
                  }}
                />

                <Typography 
                  variant="h2" 
                  component="h1" 
                  gutterBottom
                  sx={{ 
                    fontWeight: 700,
                    fontSize: { xs: '2.5rem', md: '3.5rem' },
                    lineHeight: 1.2
                  }}
                >
                  Turn <Box component="span" sx={{ color: 'primary.main' }}>"It was good"</Box> into testimonials that sell
                </Typography>

                <Typography variant="subtitle1" color="text.secondary" sx={{ mb: 4, fontSize: '1.1rem' }}>
                  Enhance bland client feedback into compelling stories that showcase your true impact—with AI that captures transformation, emotion, and results.
                </Typography>

                <Stack direction={{ xs: 'column', sm: 'row' }} spacing={2}>
                  <Button 
                    variant="contained" 
                    color="primary"
                    size="large"
                    component={RouterLink}
                    to="/enhance"
                    sx={{ px: 3, py: 1.5 }}
                    endIcon={<ArrowForwardIcon />}
                  >
                    Enhance a Testimonial
                  </Button>

                  <Button 
                    variant="outlined" 
                    color="primary"
                    size="large"
                    startIcon={<PlayArrowIcon />}
                    sx={{ px: 3, py: 1.5 }}
                    onClick={handleReset}
                  >
                    Try Demo
                  </Button>
                </Stack>

                <Box sx={{ display: 'flex', alignItems: 'center', mt: 4 }}>
                  <Box sx={{ display: 'flex', mr: 1.5 }}>
                    {[...Array(5)].map((_, i) => (
                      <StarIcon key={i} sx={{ color: '#FFD700', fontSize: 20 }} />
                    ))}
                  </Box>
                  <Typography variant="body2" color="text.secondary">
                    <Box component="span" sx={{ fontWeight: 600, color: 'text.primary' }}>4.9/5</Box> from 200+ users
                  </Typography>
                </Box>
              </Box>

              {/* Right side - Interactive Demo */}
              <Box 
                sx={{ 
                  width: { xs: '100%', md: '50%' },
                  display: 'flex',
                  justifyContent: 'center',
                  alignItems: 'flex-start',
                  mt: { xs: 2, md: 0 }
                }}
              >
                <Card 
                  ref={demoRef}
                  elevation={3}
                  sx={{ 
                    width: '100%', 
                    maxWidth: 450,
                    borderRadius: 3,
                    overflow: 'visible',
                    bgcolor: '#FCFCFF',
                    p: 3,
                    borderRadius: 4,
                    boxShadow: spotlightActive ? '0 0 30px rgba(99, 102, 241, 0.6)' : '0 10px 40px rgba(0, 0, 0, 0.08)',
                    border: '1px solid rgba(99, 102, 241, 0.1)',
                    transition: 'all 0.5s ease',
                    transform: spotlightActive ? 'scale(1.05)' : 'scale(1)',
                    position: 'relative',
                    overflow: 'visible',
                    zIndex: spotlightActive ? 1200 : 1
                  }}
                >
                  <CardContent sx={{ p: 0 }}>
                    {/* Demo Header */}
                    <Box sx={{ 
                      p: 2, 
                      borderBottom: '1px solid rgba(0, 0, 0, 0.08)',
                      display: 'flex',
                      alignItems: 'center',
                      justifyContent: 'space-between'
                    }}>
                      <Typography variant="h6" sx={{ fontWeight: 600 }}>
                        Try It Yourself
                      </Typography>
                      <Button 
                        size="small" 
                        onClick={handleReset}
                        startIcon={<PlayArrowIcon />}
                      >
                        Restart
                      </Button>
                    </Box>

                    {/* Stepper */}
                    <Stepper 
                      activeStep={activeStep} 
                      sx={{ 
                        px: 3, 
                        py: 2,
                        '& .MuiStepConnector-line': {
                          borderColor: theme.palette.primary.light
                        }
                      }}
                      alternativeLabel
                    >
                      {steps.map((label, index) => (
                        <Step key={label} completed={completed[index]}>
                          <StepButton onClick={handleStep(index)}>
                            <StepLabel StepIconProps={{
                              sx: {
                                '&.Mui-active': {
                                  color: theme.palette.primary.main
                                },
                                '&.Mui-completed': {
                                  color: '#4CAF50'
                                }
                              }
                            }}>
                              {label}
                            </StepLabel>
                          </StepButton>
                        </Step>
                      ))}
                    </Stepper>

                    {/* Step Content */}
                    <Box sx={{ p: 3, minHeight: 300 }}>
                      {activeStep === 0 && (
                        <Fade in={activeStep === 0}>
                          <Box>
                            <Typography variant="subtitle2" color="text.secondary" gutterBottom>
                              Original Client Testimonial
                            </Typography>
                            <TextField
                              fullWidth
                              multiline
                              rows={4}
                              variant="outlined"
                              value={originalText}
                              placeholder="Enter your client's original testimonial here..."
                              sx={{ mb: 3 }}
                            />
                            <Button
                              variant="contained"
                              color="primary"
                              endIcon={<AutoAwesomeIcon />}
                              onClick={handleNext}
                              fullWidth
                              sx={{ py: 1.5 }}
                            >
                              Enhance Testimonial
                            </Button>
                          </Box>
                        </Fade>
                      )}

                      {activeStep === 1 && (
                        <Fade in={activeStep === 1}>
                          <Box>
                            <Box sx={{ display: 'flex', alignItems: 'center', mb: 2 }}>
                              <AutoAwesomeIcon sx={{ color: theme.palette.primary.main, mr: 1 }} />
                              <Typography variant="subtitle2" color="primary.main">
                                AI-Enhanced Testimonial
                              </Typography>
                            </Box>

                            <Paper 
                              elevation={0} 
                              sx={{ 
                                p: 2, 
                                mb: 3, 
                                bgcolor: 'rgba(93, 95, 239, 0.05)',
                                border: '1px solid rgba(93, 95, 239, 0.2)',
                                borderRadius: 2
                              }}
                            >
                              <Typography variant="body1">
                                {enhancedText}
                              </Typography>
                            </Paper>

                            <Box sx={{ display: 'flex', gap: 2 }}>
                              <Button
                                variant="outlined"
                                color="primary"
                                startIcon={<EditIcon />}
                                onClick={handleStep(0)}
                                sx={{ flexGrow: 1 }}
                              >
                                Edit
                              </Button>
                              <Button
                                variant="contained"
                                color="primary"
                                endIcon={<SendIcon />}
                                onClick={handleNext}
                                sx={{ flexGrow: 2 }}
                              >
                                Send for Approval
                              </Button>
                            </Box>
                          </Box>
                        </Fade>
                      )}

                      {activeStep === 2 && (
                        <Fade in={activeStep === 2}>
                          <Box>
                            <Box 
                              sx={{ 
                                p: 3, 
                                mb: 3, 
                                bgcolor: 'rgba(76, 175, 80, 0.05)',
                                border: '1px solid rgba(76, 175, 80, 0.2)',
                                borderRadius: 2,
